        // Print some detailed info to the console area to illustrate internal representation
        let out = '';
        out += 'Broken internal sum (Number): ' + brokenSum + '\n';
        out += 'Expected (from cents) as Number: ' + expectedSum + '\n\n';
        out += 'Broken items internal representation:\n';
        brokenItems.forEach((it,idx)=>{
          out += idx + ': name=' + it.name + ', priceNumber=' + it.priceNumber + '\n';
          // show to 20 decimal places to reveal binary rounding
