        });
        out += '\nFixed items internal cents:\n';
        fixedItems.forEach((it,idx)=>{
          out += idx + ': name=' + it.name + ', cents=' + it.priceCents + '\n';
        });

        out += '\nNote: Many decimal fractions (like 0.99) do not have exact binary representations. That means ' +
          'operations like addition can produce tiny rounding errors: 4.99 + 9.99 might become 14.9800000000000004 in binary float.\n';
        out += 'Using === to compare a float sum to an expected decimal value can fail because the two numbers are not bitwise-identical even if they look the same when formatted.\n';
        out += 'Fix: do money math in integers (cents) or use a decimal library (big.js, decimal.js, BigInt with fixed scale, or currency-specific libraries).';
