  <script>
    // Utility: format cents to dollars string
    function formatCents(cents) {
      const sign = cents < 0 ? "-" : "";
      const a = Math.abs(cents);
      const dollars = Math.floor(a / 100);
      const rem = a % 100;
      return sign + dollars + "." + (rem < 10 ? "0" + rem : rem);
    }

    // Parse a user-provided price string into a JS Number (broken) and cents (fixed).
    function parsePriceToNumber(str) {
      // naive parse
      const n = Number(str);
      return n;
    }
    function parsePriceToCents(str) {
      // Robust parse to cents:
      // 1) Trim
      // 2) Accept formats like "4.99", ".99", "4", "4.9" -> treat as 4.90
      // 3) Multiply and round to nearest cent to avoid float imprecision at parse time
      const s = String(str).trim();
      if (s === "") return NaN;
      // Use regex to extract sign, integer and fractional parts
      const m = s.match(/^([+-])?(\d*)(?:\.(\d*))?$/);
      if (!m) return NaN;
      const sign = m[1] === "-" ? -1 : 1;
      const intPart = m[2] === "" ? "0" : m[2];
      let frac = (m[3] || "");
      if (frac.length > 2) {
        // More than 2 decimal places: round to 2
        // To avoid floating errors, take first 3 digits and round.
        const third = parseInt(frac[2] || "0", 10);
        const firstTwo = parseInt(frac.slice(0,2).padEnd(2,"0"), 10);
        const rounded = (third >= 5) ? firstTwo + 1 : firstTwo;
        frac = (rounded).toString().padStart(2,"0");
      } else {
        frac = frac.padEnd(2,"0");
      }
      const cents = sign * (parseInt(intPart,10) * 100 + parseInt(frac,10));
      return cents;
    }

    // Broken cart: uses floats
    const brokenCart = [];
    // Fixed cart: uses cents
    const fixedCart = [];

    function render() {
