      const brokenSum = brokenCart.reduce((s,it)=> s + it.price, 0);
      document.getElementById("brokenSubtotal").textContent = "$" + (isNaN(brokenSum) ? "NaN" : brokenSum.toFixed(20));
      // equality checks for demonstration
      const first = brokenCart[0] ? brokenCart[0].price : undefined;
      const eqCheckEl = document.getElementById("eqCheck");
