                       "<td>$" + formatCents(it.cents) + "</td>" +
                       "<td>" + it.cents + "¢</td>";
        fixedTbody.appendChild(tr);
      }
      const fixedSum = fixedCart.reduce((s,it) => s + it.cents, 0);
      document.getElementById("fixedSubtotal").textContent = "$" + formatCents(fixedSum);
      const dbgFixed = [
        "Fixed cart internal cents:",
        ...fixedCart.map(it => it.name + " -> " + it.cents + "¢")
      ];
      dbgFixed.push("");
      dbgFixed.push("Equality/arithmetics on integers are exact. Example: 499 + 1 = " + (499 + 1) + " cents -> $" + formatCents(499 + 1));
      document.getElementById("fixedDebug").textContent = dbgFixed.join("\n");
    }

    function escapeHtml(s) {
      return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
    }

    document.getElementById("add").addEventListener("click", function(){
