  <script>
    // Utility: parse decimal string to JS Number (naive)
    function parsePriceNumber(text) {
      // parseFloat handles common input like "4.99"
      var n = parseFloat(text);
      if (Number.isNaN(n)) throw new Error("Invalid price");
      return n;
    }

    // Utility: parse decimal string to integer cents safely
    function parsePriceToCents(text) {
      // Strategy: avoid parseFloat -> rounding issues by splitting on decimal point.
      // Accepts formats like "4.99", "4", "4.9", ".99"
      var s = String(text).trim();
      if (s === "") throw new Error("Empty price");
      // optional leading + sign
      if (/^\+/.test(s)) s = s.slice(1);
      // handle scientific notation by falling back to Number if needed
      if (/e/i.test(s)) {
        // convert to Number then to cents with rounding
        var num = Number(s);
        if (!Number.isFinite(num)) throw new Error("Invalid price");
        return Math.round(num * 100);
      }
      var parts = s.split(".");
      var dollars = parts[0] === "" ? "0" : parts[0];
      var cents = parts[1] || "";
      // remove any non-digits (defensive)
      if (!/^-?\d+$/.test(dollars) && !/^\d+$/.test(dollars)) {
        // maybe there's a negative sign
        if (/^-?\d+$/.test(dollars)) { /* ok */ } else throw new Error("Invalid dollars part");
      }
      if (!/^\d*$/.test(cents)) throw new Error("Invalid cents part");
      // normalize cents to 2 digits by right-padding with zeros, then trim extra digits with rounding
      if (cents.length > 2) {
        // round to nearest cent
        var rounded = Math.round(Number(dollars + "." + cents) * 100);
        return rounded;
      }
      while (cents.length < 2) cents = cents + "0";
      var sign = 1;
      if (dollars.startsWith("-")) { sign = -1; dollars = dollars.slice(1); }
      var dollarsInt = parseInt(dollars || "0", 10);
      var centsInt = parseInt(cents || "00", 10);
      return sign * (dollarsInt * 100 + centsInt);
    }

    // Carts
    var brokenCart = []; // items: {name, price: Number}
    var fixedCart = [];  // items: {name, priceCents: integer}

    var addLog = document.getElementById("addLog");
    var brokenLog = document.getElementById("brokenLog");
    var fixedLog = document.getElementById("fixedLog");
    var brokenTbody = document.querySelector("#brokenItems tbody");
    var fixedTbody = document.querySelector("#fixedItems tbody");

    function renderCarts() {
      // broken
      brokenTbody.innerHTML = "";
      brokenCart.forEach(function(it) {
        var tr = document.createElement("tr");
        var td1 = document.createElement("td"); td1.textContent = it.name;
        var td2 = document.createElement("td"); td2.textContent = it.price + " (" + it.price.toString() + ")";
        tr.appendChild(td1); tr.appendChild(td2);
        brokenTbody.appendChild(tr);
      });
      // fixed
      fixedTbody.innerHTML = "";
      fixedCart.forEach(function(it) {
        var tr = document.createElement("tr");
        var td1 = document.createElement("td"); td1.textContent = it.name;
        var td2 = document.createElement("td"); td2.textContent = it.priceCents + "¢";
        var td3 = document.createElement("td"); td3.textContent = (it.priceCents/100).toFixed(2);
        tr.appendChild(td1); tr.appendChild(td2); tr.appendChild(td3);
        fixedTbody.appendChild(tr);
      });
    }

    document.getElementById("addBtn").addEventListener("click", function() {
      var name = document.getElementById("itemName").value || "(unnamed)";
      var priceStr = document.getElementById("priceText").value;
      try {
        // Broken: parse as Number
        var numPrice = parsePriceNumber(priceStr);
        brokenCart.push({ name: name, price: numPrice });

        // Fixed: parse to integer cents
        var cents = parsePriceToCents(priceStr);
        fixedCart.push({ name: name, priceCents: cents });

        addLog.textContent = "Added \"" + name + "\" at " + priceStr + " to both carts.\n";
        addLog.textContent += "Broken internal stored Number: " + numPrice + "\n";
        addLog.textContent += "Fixed stored cents: " + cents + " (displayed " + (cents/100).toFixed(2) + ")\n";
      } catch (e) {
        addLog.textContent = "Error: " + e.message;
      }
      renderCarts();
    });

    document.getElementById("clearBtn").addEventListener("click", function() {
      brokenCart = [];
      fixedCart = [];
      addLog.textContent = "Carts cleared.";
      brokenLog.textContent = "";
      fixedLog.textContent = "";
      renderCarts();
    });

    document.getElementById("showBrokenTotal").addEventListener("click", function() {
      // Naive sum with floating-point numbers
      var total = 0;
      brokenCart.forEach(function(it) { total += it.price; });
      // display also toString with many decimals
      brokenLog.innerHTML = "Naive floating-point sum: " + total + "\n";
      brokenLog.innerHTML += "Number.toString(): " + total.toString() + "\n";
      brokenLog.innerHTML += "Number.toPrecision(17): " + total.toPrecision(17) + "\n\n";
      // Show typical example: sum of three 4.99 items
      var example = 0;
      for (var i=0;i<3;i++) example += 4.99;
      brokenLog.innerHTML += "Example: 4.99 + 4.99 + 4.99 = " + example + " (toPrecision: " + example.toPrecision(17) + ")\n";
      brokenLog.innerHTML += "\nNote: you may see values like 14.969999999999999 due to binary representation.\n";
    });

    document.getElementById("showFixedTotal").addEventListener("click", function() {
      var totalCents = fixedCart.reduce(function(acc, it) { return acc + it.priceCents; }, 0);
      var dollars = (totalCents / 100).toFixed(2);
      fixedLog.innerHTML = "Total cents (exact integer): " + totalCents + "¢\n";
      fixedLog.innerHTML += "Displayed as dollars: $" + dollars + "\n";
      // Also show that repeated addition yields exact cents
      var exampleCents = 0;
      for (var i=0;i<3;i++) exampleCents += 499;
      fixedLog.innerHTML += "Example fixed: 499 + 499 + 499 cents = " + exampleCents + "¢ -> $" + (exampleCents/100).toFixed(2) + "\n";
    });

    document.getElementById("demoBrokenCompare").addEventListener("click", function() {
      // Check whether any price === 4.99
      var target = 4.99;
      var found = brokenCart.some(function(it) { return it.price === target; });
      var listMatches = brokenCart.filter(function(it) { return it.price === target; }).map(function(it){ return it.name; });
      var out = "";
      out += "Checking strict equality (===) against Number 4.99\n";
      out += "Target value: " + target + " (toPrecision: " + target.toPrecision(17) + ")\n\n";
      out += "Found (===)?: " + found + "\n";
      out += "Items matching (===): " + (listMatches.length ? listMatches.join(", ") : "(none)") + "\n\n";
      out += "But values stored in broken cart (toPrecision) are:\n";
      brokenCart.forEach(function(it,i){
        out += i + ": " + it.name + " -> " + it.price + " (toPrecision: " + it.price.toPrecision(17) + ")\n";
      });
      out += "\nExplanation: The literal 4.99 you wrote in code and the parsed Number from user input may be the same mathematical value, but the binary representation might differ slightly due to parsing, rounding, or previous arithmetic, causing === to be false.\n";
      brokenLog.textContent = out;
    });

    document.getElementById("demoFixedCompare").addEventListener("click", function() {
      // Check whether any priceCents === 499
      var targetCents = 499;
      var found = fixedCart.some(function(it) { return it.priceCents === targetCents; });
      var listMatches = fixedCart.filter(function(it) { return it.priceCents === targetCents; }).map(function(it){ return it.name; });
      var out = "";
      out += "Checking strict equality (===) against integer 499 (cents)\n\n";
      out += "Found (===)?: " + found + "\n";
      out += "Items matching (===): " + (listMatches.length ? listMatches.join(", ") : "(none)") + "\n\n";
      out += "Values stored in fixed cart (cents):\n";
      fixedCart.forEach(function(it,i){
        out += i + ": " + it.name + " -> " + it.priceCents + "¢\n";
      });
      out += "\nExplanation: integer cents are exact, so strict equality behaves as expected.\n";
      fixedLog.textContent = out;
    });

    // Pre-populate with some items that demonstrate the issue quickly
    (function seed(){
      var seeds = [
        {name: "Item A", price: "4.99"},
        {name: "Item B", price: "4.99"},
        {name: "Item C", price: "4.99"}
      ];
      seeds.forEach(function(s){ 
        try {
          brokenCart.push({name: s.name, price: parsePriceNumber(s.price)});
          fixedCart.push({name: s.name, priceCents: parsePriceToCents(s.price)});
        } catch(e) {}
      });
      renderCarts();
      addLog.textContent = "Seeded 3 items priced 4.99 each. Click 'Show broken total' and 'Show fixed total' to compare.";
