<script>
/* Helper formatting */
function fmtUSD(n) {
  return '$' + Number(n).toFixed(2);
}
function fmtUSDfromCents(cents) {
  // cents may be BigInt or number
  let c = typeof cents === 'bigint' ? Number(cents) : cents;
  return '$' + (c/100).toFixed(2);
}

/* BROKEN cart (uses floats) */
const brokenState = { items: [] }; // each item: {name, price: Number, qty}
const bItemsTbody = document.getElementById('broken-items');
const bTotalEl = document.getElementById('b-total');
const bExpEl = document.getElementById('b-exp');
const bLog = document.getElementById('b-log');

function renderBroken() {
  bItemsTbody.innerHTML = '';
  brokenState.items.forEach((it, i) => {
