    bItemsTbody.appendChild(tr);
  });
  const total = brokenState.items.reduce((s, it) => s + it.price * it.qty, 0);
  // "Expected" calculated by converting decimals using string -> Number with two decimal places (what a naive dev might think)
  const expected = brokenState.items.reduce((s, it) => s + parseFloat(it.price.toFixed(2)) * it.qty, 0);
  bTotalEl.textContent = String(total) + '  (' + fmtUSD(total) + ')';
