  message.push('  total === expected -> ' + (total === expected));
  message.push('');
  message.push('Why this fails: because decimal fractions like 0.1 or 4.99 have no exact binary representation.');
  message.push('You can observe small representation differences that break strict equality and can make totals off by a cent when formatted.');
